import type { CmsLocalizedText } from '#modula/shared/cms'

export type PublicDictionaryCategory =
  | 'navigation'
  | 'pages'
  | 'checkout'
  | 'orders'
  | 'events'
  | 'auth'
  | 'profile'
  | 'shop'

export interface PublicDictionaryDefinition {
  key: string
  category: PublicDictionaryCategory
  page: string
  label: CmsLocalizedText
  defaultValue: CmsLocalizedText
  multiline?: boolean
}

const define = (
  key: string,
  category: PublicDictionaryCategory,
  page: string,
  labelFr: string,
  labelEn: string,
  fr: string,
  en: string,
  multiline = false
): PublicDictionaryDefinition => ({
  key,
  category,
  page,
  label: { fr: labelFr, en: labelEn },
  defaultValue: { fr, en },
  multiline
})

