export type PublicDictionaryStore = Record<string, CmsLocalizedText>

export function getPublicDictionaryDefinitionMap() {
  return new Map(PUBLIC_DICTIONARY_DEFINITIONS.map(definition => [definition.key, definition]))
}

export function getPublicDictionaryDefaultStore(): PublicDictionaryStore {
  return Object.fromEntries(
    PUBLIC_DICTIONARY_DEFINITIONS.map(definition => [definition.key, { ...definition.defaultValue }])
  )
}
